import { readFile, writeFile } from "node:fs/promises";
import { createBucket, put, list } from "@tigrisdata/storage";

async function main() {
  try {
    // 1. Read the current trial_id from /logs/artifacts/trial_id
    const trialId = (await readFile("/logs/artifacts/trial_id", "utf-8")).trim();

    // 2. Build and normalize the bucket name
    const normalizedTrialId = trialId.toLowerCase().replace(/[^a-z0-9.-]/g, '-');
    const bucketName = `harbor-tssdk-${normalizedTrialId}`;

    console.log(`Using bucket name: ${bucketName}`);

    // 3. Call createBucket
    const { data: bucketData, error: bucketError } = await createBucket(bucketName);
    if (bucketError) {
      if (!bucketError.message?.toLowerCase().includes("exist")) {
        console.error("Failed to create bucket:", bucketError);
        process.exit(1);
      } else {
        console.log("Bucket already exists, continuing...");
      }
    } else {
      console.log("Bucket created successfully.");
    }

    // 4. Call put three times
    const objects = [
      { key: "inbox/msg-1.json", body: '{"id": 1}' },
      { key: "inbox/msg-2.json", body: '{"id": 2}' },
      { key: "inbox/msg-3.json", body: '{"id": 3}' },
    ];

    for (const obj of objects) {
      console.log(`Uploading ${obj.key}...`);
      const { data, error } = await put(obj.key, obj.body, {
        config: { bucket: bucketName },
        contentType: "application/json"
      });
      if (error) {
        console.error(`Failed to upload ${obj.key}:`, error);
        process.exit(1);
      }
    }
    console.log("All objects uploaded successfully.");

    // 5. Call list with { prefix: "inbox/" }
    console.log("Listing objects...");
    const { data: listData, error: listError } = await list({
      prefix: "inbox/",
      config: { bucket: bucketName }
    });

    if (listError) {
      console.error("Failed to list objects:", listError);
      process.exit(1);
    }

    const itemNames = listData?.items?.map(item => item.name) || [];

    // Write resulting object names to /home/user/tigris-task/listing.txt
    await writeFile("/home/user/tigris-task/listing.txt", itemNames.join("\n"));
    console.log("Listing written to listing.txt");

  } catch (err) {
    console.error("Unexpected error:", err);
    process.exit(1);
  }
}

main();
